    // deals cards from the deck
    public static ArrayList<Card> drawHand(Stack<Card> deck) {
        ArrayList<Card> hand = new ArrayList<Card>();
        for (int i = 0; i <= 4; i++) {
            Card card = deck.pop();
            hand.add(card);
        }
        return hand;
    }

